actions.action:
Load safe zone definitions for the target aspect ratio:
- 16:9: title_safe { top: 5%, bottom: 5%, left: 5%, right: 5% }
- 9:16: title_safe { top: 10%, bottom: 15%, left: 8%, right: 8% }, caption_zone { top: 60%, bottom: 85% }
- 1:1: title_safe { top: 8%, bottom: 8%, left: 8%, right: 8% }

task.output_schema:

# Derived scene-spec.yaml for {target_format}

episode_id: "{episode_id}"
format: "{target_format}"
derived_from: "episodes/{episode_id}/ssd/scene-spec.yaml"
generated_at: "{ISO-8601 timestamp}"

format_metadata:
  name: "{format name}"
  aspect_ratio: "{aspect_ratio}"
  resolution: "{resolution}"
  max_duration: {seconds}
  crop_strategy: "{default strategy}"

adaptation_summary:
  original_scene_count: {int}
  included_scene_count: {int}
  excluded_scene_count: {int}
  original_duration: {seconds}
  adapted_duration: {seconds}
  has_hook: {boolean}
  has_cta: {boolean}

scenes:
  - scene_id: "{scene_id}"
    original_duration: {seconds}
    adapted_duration: {seconds}
    priority: "{essential|important|supplementary}"
    crop_strategy: "{none|center-crop|center-subject|letterbox|pan-scan}"
    crop_metadata: {}
    # ... all other original scene properties preserved

excluded_scenes:
  - scene_id: "{scene_id}"
    priority: "{priority}"
    reason: "{over_time_budget|low_priority|...}"
